func TestToggleHidden_FromHidden(t *testing.T) {
	ctx := testContext(map[string]string{
		"com.apple.finder.AppleShowAllFiles": "false",
	})
	mod := &FinderModule{}
	if err := mod.toggleHidden(ctx); err != nil {
		t.Fatalf("toggleHidden failed: %v", err)
