	// TODO: implement with bufio.Scanner
	return "", nil
}

func (TerminalPrompt) Select(msg string, opts []string) (int, error) {
	// TODO: implement with bufio.Scanner
	return -1, nil
}

// AutoYesPrompt always returns true/empty/first — used when --yes flag is set.
