39	)
40	
41	func main() {
42		rootCmd := &cobra.Command{
43			Use:   "mac",
44			Short: "SuperMac — macOS power tools for the CLI",
45			Long:  "Professional command-line tool for macOS with organized, powerful shortcuts.\nBuilt by CosmoLabs — https://cosmolabs.org",
46			Run:   runHelp,
47		}
48	
49		rootCmd.PersistentFlags().BoolVar(&jsonFlag, "json", false, "Output in JSON format")
50		rootCmd.PersistentFlags().BoolVar(&quietFlag, "quiet", false, "Suppress all output except errors")
51		rootCmd.PersistentFlags().BoolVar(&noColor, "no-color", false, "Disable color output")
52		rootCmd.PersistentFlags().BoolVarP(&verbose, "verbose", "v", false, "Verbose output")
53		rootCmd.PersistentFlags().BoolVar(&dryRun, "dry-run", false, "Show what would be done without executing")
54		rootCmd.PersistentFlags().BoolVarP(&yesFlag, "yes", "y", false, "Skip confirmation prompts")
55	
56		// Built-in commands
57		rootCmd.AddCommand(versionCmd())
58		rootCmd.AddCommand(configCmd())
59	
60		// Register all modules as Cobra subcommands
61		registerModules(rootCmd)
62	
63		// Global shortcuts (convenience aliases matching the original Bash CLI)
64		addShortcuts(rootCmd)
65	
66		if err := rootCmd.Execute(); err != nil {
67			os.Exit(1)
68		}
69	}
70	
71	func versionCmd() *cobra.Command {
72		return &cobra.Command{
73			Use:   "version",
74			Short: "Show version information",
75			Run: func(cmd *cobra.Command, args []string) {
76				w := getOutput()
77				w.Header(fmt.Sprintf("SuperMac v%s", version.Version))
78				fmt.Printf("  Version:    %s\n", version.Version)
79				fmt.Printf("  Build:      %s\n", version.BuildDate)
80				fmt.Println()
81	
82				modules := module.All()
83				names := make([]string, 0, len(modules))
84				for name := range modules {
85					names = append(names, name)
86				}
87				sort.Strings(names)
88				fmt.Printf("  Modules:    %s\n", strings.Join(names, ", "))
89			},
90		}
91	}
92	
93	func configCmd() *cobra.Command {
94		cmd := &cobra.Command{
95			Use:   "config",
96			Short: "Manage SuperMac configuration",
97		}
98	
99		cmd.AddCommand(&cobra.Command{
100			Use:   "list",
101			Short: "Show current configuration",
102			Run: func(cmd *cobra.Command, args []string) {
103				cfg, err := config.Load()
104				if err != nil {
105					fmt.Fprintf(os.Stderr, "Error loading config: %v\n", err)
106					os.Exit(1)
107				}
108				w := getOutput()
109				if jsonFlag {
110					w.JSON(cfg)
111					return
112				}
113				w.Header("SuperMac Configuration")
114				fmt.Printf("  Format:   %s\n", cfg.Output.Format)
115				fmt.Printf("  Color:    %v\n", cfg.Output.Color)
116				fmt.Printf("  Updates:  %v (%s)\n", cfg.Output.Format, cfg.Updates.Channel)
117				if len(cfg.Aliases) > 0 {
118					fmt.Println("  Aliases:")
119					for k, v := range cfg.Aliases {
120						fmt.Printf("    %-15s → %s\n", k, v)
121					}
122				}
123			},
124		})
125	
126		cmd.AddCommand(&cobra.Command{
127			Use:   "get <key>",
128			Short: "Get a config value",
129			Args:  cobra.ExactArgs(1),
130			Run: func(cmd *cobra.Command, args []string) {
131				cfg, err := config.Load()
132				if err != nil {
133					fmt.Fprintf(os.Stderr, "Error: %v\n", err)
134					os.Exit(1)
135				}
136				// Simple dot-path lookup
137				switch args[0] {
138				case "output.format":
139					fmt.Println(cfg.Output.Format)
140				case "output.color":
141					fmt.Println(cfg.Output.Color)
142				case "updates.check":
143					fmt.Println(cfg.Updates.Check)
144				case "updates.channel":
145					fmt.Println(cfg.Updates.Channel)
146				default:
147					fmt.Fprintf(os.Stderr, "Unknown config key: %s\n", args[0])
148					os.Exit(1)
149				}
150			},
151		})
152	
153		return cmd
154	}
155	
156	func registerModules(rootCmd *cobra.Command) {
157		modules := module.All()
158	
159		for _, mod := range modules {
160			modCmd := &cobra.Command{
161				Use:   mod.Name(),
162				Short: fmt.Sprintf("%s %s", mod.Emoji(), mod.ShortDescription()),
163			}
164	
165			commands := mod.Commands()
166			for _, cmd := range commands {
167				cmd := cmd // capture
168				subCmd := &cobra.Command{
169					Use:   cmd.Name,
170					Short: cmd.Description,
171					Aliases: cmd.Aliases,
172					RunE: func(subCmd *cobra.Command, args []string) error {
173						ctx := &module.Context{
174							Config:   loadConfig(),
175							Output:   getOutput(),
176							Platform: getPlatform(),
177							Prompt:   getPrompt(),
178							Args:     args,
179							Flags:    make(map[string]string),
180							Verbose:  verbose,
181							DryRun:   dryRun,
182						}
183						return cmd.Run(ctx)
184					},
185				}
186				// Register per-command flags
187				for _, flag := range cmd.Flags {
188					subCmd.Flags().StringP(flag.Name, flag.Shorthand, flag.DefaultValue, flag.Description)
189					if flag.Required {
190						subCmd.MarkFlagRequired(flag.Name)
191					}
192				}
193				modCmd.AddCommand(subCmd)
194			}
195	
196			rootCmd.AddCommand(modCmd)
197		}
198	}
199	
200	func runHelp(cmd *cobra.Command, args []string) {
201		w := getOutput()
202		w.Header(fmt.Sprintf("SuperMac v%s", version.Version))
203		fmt.Println()
204		fmt.Println("Usage: mac <category> <action> [arguments]")
205		fmt.Println()
206	
207		modules := module.All()
208		if len(modules) > 0 {
209			names := make([]string, 0, len(modules))
210			for name := range modules {
211				names = append(names, name)
212			}
213			sort.Strings(names)
214	
215			fmt.Println("Available Categories:")
216			for _, name := range names {
217				mod := modules[name]
218				fmt.Printf("  %-12s %s %s\n", name, mod.Emoji(), mod.ShortDescription())
219			}
220			fmt.Println()
221		}
222	
223		fmt.Println("Built-in Commands:")
224		fmt.Println("  help           Show this help")
225		fmt.Println("  version        Show version information")
226		fmt.Println("  config list    Show current configuration")
227		fmt.Println()
228		fmt.Println("Global Flags:")
229		fmt.Println("  --json         Output in JSON format")
230		fmt.Println("  --quiet        Suppress output except errors")
231		fmt.Println("  --no-color     Disable color output")
232		fmt.Println("  --verbose      Verbose output")
233		fmt.Println("  --dry-run      Show what would be done")
234		fmt.Println("  --yes          Skip confirmation prompts")
235		fmt.Println()
236		fmt.Println("Built by CosmoLabs — https://cosmolabs.org")
237	}
238	
239	func loadConfig() *config.Config {
240		cfg, err := config.Load()
241		if err != nil {
242			return config.Default()
243		}
244		return cfg
245	}
246	
247	func getOutput() output.Writer {
248		format := "text"
249		if jsonFlag {
250			format = "json"
251		} else if quietFlag {
252			format = "quiet"
253		}
254		return output.NewWriter(format, os.Stdout)
255	}
256	
257	func getPlatform() platform.Interface {
258		return &platform.DarwinPlatform{}
259	}
260	
261	func getPrompt() module.PromptInterface {
262		if yesFlag {
263			return &module.AutoYesPrompt{}
264		}
265		return &module.TerminalPrompt{}
266	}
267	
268	// addShortcuts creates top-level convenience commands that delegate to module subcommands.
269	// These mirror the original Bash CLI's global shortcuts.
270	func addShortcuts(rootCmd *cobra.Command) {
271		shortcuts := map[string]string{
272			"ip":             "network ip",
273			"cleanup":        "system cleanup",
274			"restart-finder": "finder restart",
275			"kp":             "dev kill-port",
276			"vol":            "audio volume",
277			"dark":           "display dark-mode on",
278			"light":          "display dark-mode off",
279			"search":         "", // special: built-in search
280		}
281	
282		for name, target := range shortcuts {
283			if name == "search" {
284				// Search command: find commands by keyword
285				rootCmd.AddCommand(&cobra.Command{
286					Use:   "search <term>",
287					Short: "Search for a command by keyword",
288					Args:  cobra.MinimumNArgs(1),
289					Run: func(cmd *cobra.Command, args []string) {
290						term := strings.ToLower(args[0])
291						w := getOutput()
292						w.Header("Search Results")
