								sc.RunE(sc, args)
								return
							}
						}
					}
				}
				fmt.Fprintf(os.Stderr, "Error: shortcut target 'mac %s' not found\n", shortcutModule+" "+shortcutSubCmd)
				os.Exit(1)
			},
		})
	}
}

