package dep

import (
	"fmt"
	"os"
	"os/exec"
	"strings"

	"github.com/cosmolabs-org/supermac/internal/module"
)

// Dependency describes an external tool required by a module.
type Dependency struct {
	Name     string   // display name: "blueutil"
	Brew     string   // brew formula name: "blueutil"
	Check    string   // binary to look for on PATH: "blueutil"
	Commands []string // which commands need this (nil = all commands in module)
}

// IsInstalled checks whether the dependency binary exists on PATH.
func (d Dependency) IsInstalled() bool {
	_, err := exec.LookPath(d.Check)
	return err == nil
}

// Install runs brew install for the dependency.
func (d Dependency) Install() error {
	brew, err := exec.LookPath("brew")
	if err != nil {
		return fmt.Errorf("Homebrew is not installed. Install it from https://brew.sh")
	}
	cmd := exec.Command(brew, "install", d.Brew)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	return cmd.Run()
}

// Ensure checks if the dependency is installed. If not and interactive is true,
// it prompts the user to install via Homebrew. If interactive is false, it returns an error.
func (d Dependency) Ensure(interactive bool) error {
	if d.IsInstalled() {
		return nil
	}

	if !interactive {
		return module.NewExitError(module.ExitNotFound,
			fmt.Sprintf("%s is not installed. Install with: brew install %s", d.Name, d.Brew))
	}

	// Auto-install with --yes flag or prompt
	if os.Getenv("SUPERMAC_AUTO_INSTALL") == "1" {
		fmt.Printf("  Installing %s via Homebrew...\n", d.Name)
		if err := d.Install(); err != nil {
			return fmt.Errorf("failed to install %s: %w", d.Name, err)
		}
		fmt.Printf("  ✓ %s installed successfully.\n", d.Name)
		return nil
	}

	fmt.Printf("\n  %s is not installed.\n", d.Name)
	fmt.Printf("  Install via Homebrew? [Y/n]: ")

	var response string
	fmt.Scanln(&response)
	response = strings.TrimSpace(strings.ToLower(response))

	if response != "" && response != "y" && response != "yes" {
		return module.NewExitError(module.ExitNotFound,
			fmt.Sprintf("%s is required. Install with: brew install %s", d.Name, d.Brew))
	}

	fmt.Printf("  Installing %s...\n", d.Name)
	if err := d.Install(); err != nil {
		return fmt.Errorf("failed to install %s: %w", d.Name, err)
	}
	fmt.Printf("  ✓ %s installed successfully.\n\n", d.Name)
	return nil
}

// AffectsCommand returns true if this dependency is needed for the given command.
func (d Dependency) AffectsCommand(commandName string) bool {
	if d.Commands == nil {
		return true // affects all commands
	}
	for _, c := range d.Commands {
		if c == commandName {
			return true
		}
	}
	return false
}

// CheckBrew returns true if Homebrew is installed and provides its path.
func CheckBrew() (string, bool) {
	path, err := exec.LookPath("brew")
	if err != nil {
		return "", false
	}
	return path, true
}

package dep

import (
	"testing"
)

func TestIsInstalled_KnownBinary(t *testing.T) {
	// "ls" exists on every macOS
	d := Dependency{Name: "ls", Check: "ls"}
	if !d.IsInstalled() {
		t.Error("expected ls to be installed")
	}
}

func TestIsInstalled_UnknownBinary(t *testing.T) {
	d := Dependency{Name: "nonexistent-tool-xyz", Check: "nonexistent-tool-xyz"}
	if d.IsInstalled() {
		t.Error("expected nonexistent binary to not be installed")
	}
}

func TestAffectsCommand_NilCommands(t *testing.T) {
	d := Dependency{Name: "test", Commands: nil}
	if !d.AffectsCommand("anything") {
		t.Error("nil Commands should affect all commands")
	}
}

func TestAffectsCommand_SpecificCommands(t *testing.T) {
	d := Dependency{Name: "test", Commands: []string{"add", "remove"}}
	if !d.AffectsCommand("add") {
		t.Error("should affect 'add'")
	}
	if !d.AffectsCommand("remove") {
		t.Error("should affect 'remove'")
	}
	if d.AffectsCommand("list") {
		t.Error("should not affect 'list'")
	}
}

func TestEnsure_NonInteractive(t *testing.T) {
	d := Dependency{Name: "nonexistent-tool-xyz", Brew: "nonexistent", Check: "nonexistent-tool-xyz"}
	err := d.Ensure(false)
	if err == nil {
		t.Error("expected error for missing dep in non-interactive mode")
	}
}

func TestCheckBrew(t *testing.T) {
	path, ok := CheckBrew()
	// brew may or may not be installed in CI, just verify no panic
	_ = path
	_ = ok
}

