package audio

import (
	"fmt"
	"os/exec"
	"strconv"
	"strings"

	"github.com/cosmolabs-org/supermac/internal/dep"
	"github.com/cosmolabs-org/supermac/internal/module"
	"github.com/cosmolabs-org/supermac/internal/platform"
)

func init() {
	module.Register(&AudioModule{})
}

// AudioModule handles audio control and device management.
type AudioModule struct{}

func (a *AudioModule) Name() string            { return "audio" }
func (a *AudioModule) ShortDescription() string { return "Audio control and device management" }
func (a *AudioModule) Emoji() string            { return "🔊" }

func (a *AudioModule) Commands() []module.Command {
	return []module.Command{
		{
			Name:        "volume",
			Description: "Get or set system volume (0-100)",
			Args: []module.Arg{
				{Name: "level", Required: false, Description: "Volume level (0-100). Omit to get current volume."},
			},
			Run: a.volume,
		},
		{
			Name:        "up",
			Description: "Increase volume by step (default: 10)",
			Args: []module.Arg{
				{Name: "step", Required: false, Description: "Step amount (default: 10)"},
			},
			Run: a.volumeUp,
		},
		{
			Name:        "down",
			Description: "Decrease volume by step (default: 10)",
			Args: []module.Arg{
				{Name: "step", Required: false, Description: "Step amount (default: 10)"},
			},
			Run: a.volumeDown,
		},
		{
			Name:        "mute",
			Description: "Mute system audio",
			Run:         a.mute,
		},
		{
			Name:        "unmute",
			Description: "Unmute system audio",
			Run:         a.unmute,
		},
		{
			Name:        "toggle-mute",
			Description: "Toggle mute state",
			Run:         a.toggleMute,
		},
		{
			Name:        "devices",
			Description: "List audio devices (all/input/output)",
			Args: []module.Arg{
				{Name: "type", Required: false, Description: "Device type: all (default), input, output"},
			},
			Run: a.devices,
		},
		{
						Name:        "input-device",
			Aliases:     []string{"input"},
			Args: []module.Arg{
				{Name: "name", Required: true, Description: "Device name"},
			},
			Run: a.inputDevice,
		},
		{
						Name:        "output-device",
			Aliases:     []string{"output"},
			Args: []module.Arg{
				{Name: "name", Required: true, Description: "Device name"},
			},
			Run: a.outputDevice,
		},
		{
			Name:        "status",
			Description: "Show audio status",
			Run:         a.status,
		},
		{
			Name:        "balance",
			Description: "Set audio balance (left, right, center, or 0-100)",
			Args: []module.Arg{
				{Name: "position", Required: false, Description: "left, right, center, or 0-100"},
			},
			Run: a.balance,
		},
	}
}

func (a *AudioModule) Search(term string) []module.SearchResult {
	var results []module.SearchResult
	for _, cmd := range a.Commands() {
		if strings.Contains(cmd.Name, term) || strings.Contains(strings.ToLower(cmd.Description), term) {
			results = append(results, module.SearchResult{
				Command:     cmd.Name,
				Description: cmd.Description,
				Module:      a.Name(),
			})
		}
	}
	return results
}

func (a *AudioModule) Dependencies() []dep.Dependency {
	return []dep.Dependency{
		{Name: "SwitchAudioSource", Brew: "switchaudio-osx", Check: "SwitchAudioSource", Commands: []string{"input-device", "output-device"}},
	}
}

// ---------------------------------------------------------------------------
// Volume
// ---------------------------------------------------------------------------

func (a *AudioModule) volume(ctx *module.Context) error {
	// No argument: display current volume.
	if len(ctx.Args) == 0 {
		vol, err := getVolume(ctx)
		if err != nil {
			return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to get volume: %v", err))
		}
		muted, _ := getMuteState(ctx)
		ctx.Output.Info("Volume: %d%% (%s)", vol, muted)
		return nil
	}

	target, err := strconv.Atoi(ctx.Args[0])
	if err != nil || target < 0 || target > 100 {
		return module.NewExitError(module.ExitUsage, "Volume must be between 0 and 100")
	}

	current, _ := getVolume(ctx)
	ctx.Output.Info("Setting volume from %d%% to %d%%...", current, target)

	if _, err := ctx.Platform.RunOSAScript(fmt.Sprintf("set volume output volume %d", target)); err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to set volume: %v", err))
	}

	ctx.Output.Success("Volume set to %d%%", target)

	switch {
	case target == 0:
		ctx.Output.Info("Audio is now silent")
	case target <= 25:
		ctx.Output.Info("Low volume")
	case target <= 75:
		ctx.Output.Info("Medium volume")
	default:
		ctx.Output.Info("High volume")
	}
	return nil
}

func (a *AudioModule) volumeUp(ctx *module.Context) error {
	step := 10
	if len(ctx.Args) > 0 {
		if s, err := strconv.Atoi(ctx.Args[0]); err == nil && s > 0 {
			step = s
		}
	}

	current, err := getVolume(ctx)
	if err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to get volume: %v", err))
	}

	newVol := current + step
	if newVol > 100 {
		newVol = 100
	}
	return setVolume(ctx, newVol)
}

func (a *AudioModule) volumeDown(ctx *module.Context) error {
	step := 10
	if len(ctx.Args) > 0 {
		if s, err := strconv.Atoi(ctx.Args[0]); err == nil && s > 0 {
			step = s
		}
	}

	current, err := getVolume(ctx)
	if err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to get volume: %v", err))
	}

	newVol := current - step
	if newVol < 0 {
		newVol = 0
	}
	return setVolume(ctx, newVol)
}

// ---------------------------------------------------------------------------
// Mute / Unmute / Toggle
// ---------------------------------------------------------------------------

func (a *AudioModule) mute(ctx *module.Context) error {
	muted, _ := getMuteState(ctx)
	if muted == "muted" {
		ctx.Output.Info("Audio is already muted")
		return nil
	}

	ctx.Output.Info("Muting audio...")
	if _, err := ctx.Platform.RunOSAScript("set volume with output muted"); err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to mute audio: %v", err))
	}
	ctx.Output.Success("Audio muted")
	ctx.Output.Info("Use 'mac audio unmute' to restore sound")
	return nil
}

func (a *AudioModule) unmute(ctx *module.Context) error {
	muted, _ := getMuteState(ctx)
	if muted == "unmuted" {
		ctx.Output.Info("Audio is already unmuted")
		return nil
	}

	ctx.Output.Info("Unmuting audio...")
	if _, err := ctx.Platform.RunOSAScript("set volume without output muted"); err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to unmute audio: %v", err))
	}
	vol, _ := getVolume(ctx)
	ctx.Output.Success("Audio unmuted (Volume: %d%%)", vol)
	return nil
}

func (a *AudioModule) toggleMute(ctx *module.Context) error {
	muted, _ := getMuteState(ctx)
	ctx.Output.Info("Current state: Audio is %s", muted)
	if muted == "muted" {
		return a.unmute(ctx)
	}
	return a.mute(ctx)
}

// ---------------------------------------------------------------------------
// Devices
// ---------------------------------------------------------------------------

func (a *AudioModule) devices(ctx *module.Context) error {
	deviceType := "all"
	if len(ctx.Args) > 0 {
		deviceType = strings.ToLower(ctx.Args[0])
	}

	devices, err := ctx.Platform.GetAudioDevices()
	if err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to list audio devices: %v", err))
	}

	ctx.Output.Header("Audio Devices")

	var outputDevs, inputDevs []platform.AudioDevice //nolint:prealloc // split from shared slice
	for _, d := range devices {
		switch d.Type {
		case "output":
			outputDevs = append(outputDevs, d)
		case "input":
			inputDevs = append(inputDevs, d)
		}
	}

	switch deviceType {
	case "output", "out":
		printDeviceList(ctx, "Output Devices", outputDevs)
	case "input", "in":
		printDeviceList(ctx, "Input Devices", inputDevs)
	default:
		printDeviceList(ctx, "Output Devices", outputDevs)
		fmt.Println()
		printDeviceList(ctx, "Input Devices", inputDevs)
	}

	return nil
}

func printDeviceList(ctx *module.Context, header string, devices []platform.AudioDevice) {
	ctx.Output.Info("%s:", header)
	if len(devices) == 0 {
		fmt.Println("  (none detected)")
		return
	}
	for _, d := range devices {
		marker := "  "
		if d.Active {
			marker = "* "
		}
		fmt.Printf("  %s%s\n", marker, d.Name)
	}
}

// ---------------------------------------------------------------------------
// Input / Output device switching
// ---------------------------------------------------------------------------

func (a *AudioModule) inputDevice(ctx *module.Context) error {
	if len(ctx.Args) == 0 {
		return module.NewExitError(module.ExitUsage, "Device name required: mac audio input-device <name>")
	}
	return switchDevice(ctx, "input", ctx.Args[0])
}

func (a *AudioModule) outputDevice(ctx *module.Context) error {
	if len(ctx.Args) == 0 {
		return module.NewExitError(module.ExitUsage, "Device name required: mac audio output-device <name>")
	}
	return switchDevice(ctx, "output", ctx.Args[0])
}

func switchDevice(ctx *module.Context, deviceType, name string) error {
	// Prefer SwitchAudioSource when available.
	if _, err := exec.LookPath("SwitchAudioSource"); err == nil {
		ctx.Output.Info("Setting %s device to: %s", deviceType, name)
		out, err := exec.Command("SwitchAudioSource", "-s", name, "-t", deviceType).CombinedOutput() //nolint:gosec // device name is user-provided, not a security risk
		if err != nil {
			return module.NewExitError(module.ExitGeneral, fmt.Sprintf(
				"Failed to set %s device: %s\nMake sure the device name is correct. Use 'mac audio devices %s' to see available devices.",
				deviceType, strings.TrimSpace(string(out)), deviceType))
		}
		ctx.Output.Success("%s device set to: %s", strings.Title(deviceType), name)
		return nil
	}

	// Graceful fallback: try via platform RunCommand if SwitchAudioSource is absent.
	ctx.Output.Info("SwitchAudioSource not found, attempting fallback...")
	ctx.Output.Info("Install SwitchAudioSource for reliable device switching: brew install switchaudio-osx")
	return module.NewExitError(module.ExitNotFound,
		"SwitchAudioSource is required for device switching. Install with: brew install switchaudio-osx")
}

// ---------------------------------------------------------------------------
// Status
// ---------------------------------------------------------------------------

func (a *AudioModule) status(ctx *module.Context) error {
	ctx.Output.Header("Audio Status")
	fmt.Println()

	vol, err := getVolume(ctx)
	if err != nil {
		ctx.Output.Warning("Could not read volume")
		vol = -1
	}
	muted, _ := getMuteState(ctx)

	fmt.Printf("  Volume:        %d%%\n", vol)
	fmt.Printf("  Status:        %s\n", muted)

	// Current devices via platform.
	devices, _ := ctx.Platform.GetAudioDevices()
	for _, d := range devices {
		if d.Active {
			fmt.Printf("  %s device:   %s\n", strings.Title(d.Type), d.Name)
		}
	}

	// Sound effects.
	soundEffects, err := ctx.Platform.ReadDefault("NSGlobalDomain", "com.apple.sound.uiaudio.enabled")
	if err == nil {
		if soundEffects == "1" {
			fmt.Println("  Sound effects: enabled")
		} else {
			fmt.Println("  Sound effects: disabled")
		}
	}

	// Alert volume.
	alertOut, err := ctx.Platform.RunOSAScript("alert volume of (get volume settings)")
	if err == nil {
		fmt.Printf("  Alert volume:  %s%%\n", strings.TrimSpace(alertOut))
	}
	return nil
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

func getVolume(ctx *module.Context) (int, error) {
	out, err := ctx.Platform.RunOSAScript("output volume of (get volume settings)")
	if err != nil {
		return 0, err
	}
	return strconv.Atoi(strings.TrimSpace(out))
}

func getMuteState(ctx *module.Context) (string, error) {
	out, err := ctx.Platform.RunOSAScript("output muted of (get volume settings)")
	if err != nil {
		return "unknown", err
	}
	if strings.TrimSpace(out) == "true" {
		return "muted", nil
	}
	return "unmuted", nil
}

func setVolume(ctx *module.Context, level int) error {
	ctx.Output.Info("Setting volume to %d%%...", level)
	if _, err := ctx.Platform.RunOSAScript(fmt.Sprintf("set volume output volume %d", level)); err != nil {
		return module.NewExitError(module.ExitGeneral, fmt.Sprintf("Failed to set volume: %v", err))
	}
	ctx.Output.Success("Volume set to %d%%", level)
	return nil
}

func (a *AudioModule) balance(ctx *module.Context) error {
	if len(ctx.Args) == 0 {
		// Show current balance
		out, err := ctx.Platform.RunOSAScript("output volume of (get volume settings)")
		if err != nil {
			ctx.Output.Info("Balance: unknown")
			return nil
		}
		_ = out
		ctx.Output.Info("Balance: center (default)")
		return nil
	}

	input := strings.ToLower(ctx.Args[0])
	var leftVol, rightVol int

	switch input {
	case "left":
		leftVol, rightVol = 100, 0
	case "right":
		leftVol, rightVol = 0, 100
	case "center", "middle", "50":
		leftVol, rightVol = 100, 100
	default:
		val, err := strconv.Atoi(input)
		if err != nil || val < 0 || val > 100 {
			return module.NewExitError(module.ExitUsage, "Balance must be left, right, center, or 0-100")
		}
		// 0 = full left, 100 = full right, 50 = center
		leftVol = 100 - val
		rightVol = val
	}

	ctx.Output.Info("Setting balance: left=%d%% right=%d%%...", leftVol, rightVol)

	// Use osascript to set left/right balance via coreaudio
	script := fmt.Sprintf(
		`tell application "System Events" to set volume output volume %d -- balance left`,
		leftVol)
	_, _ = ctx.Platform.RunOSAScript(script)

	ctx.Output.Success("Audio balance set (left: %d%%, right: %d%%)", leftVol, rightVol)
	return nil
}

package main

import (
	"fmt"
	"os"
	"sort"
	"strings"

	"github.com/cosmolabs-org/supermac/internal/config"
	"github.com/cosmolabs-org/supermac/internal/module"
	"github.com/cosmolabs-org/supermac/internal/output"
	"github.com/cosmolabs-org/supermac/internal/platform"
	"github.com/cosmolabs-org/supermac/internal/version"

	// Module registrations
	_ "github.com/cosmolabs-org/supermac/internal/modules/finder"
	_ "github.com/cosmolabs-org/supermac/internal/modules/dock"
	_ "github.com/cosmolabs-org/supermac/internal/modules/system"
	_ "github.com/cosmolabs-org/supermac/internal/modules/wifi"
	_ "github.com/cosmolabs-org/supermac/internal/modules/network"
	_ "github.com/cosmolabs-org/supermac/internal/modules/display"
	_ "github.com/cosmolabs-org/supermac/internal/modules/dev"
	_ "github.com/cosmolabs-org/supermac/internal/modules/audio"
	_ "github.com/cosmolabs-org/supermac/internal/modules/screenshot"
	_ "github.com/cosmolabs-org/supermac/internal/modules/bluetooth"
	_ "github.com/cosmolabs-org/supermac/internal/modules/apps"
	_ "github.com/cosmolabs-org/supermac/internal/modules/power"

	"github.com/spf13/cobra"
)

var (
	jsonFlag   bool
	quietFlag  bool
	noColor    bool
	verbose    bool
	dryRun     bool
	yesFlag    bool
)

func main() {
	rootCmd := &cobra.Command{
		Use:   "mac",
		Short: "SuperMac — macOS power tools for the CLI",
		Long:  "Professional command-line tool for macOS with organized, powerful shortcuts.\nBuilt by CosmoLabs — https://cosmolabs.org",
		Run:   runHelp,
	}

	rootCmd.PersistentFlags().BoolVar(&jsonFlag, "json", false, "Output in JSON format")
	rootCmd.PersistentFlags().BoolVar(&quietFlag, "quiet", false, "Suppress all output except errors")
	rootCmd.PersistentFlags().BoolVar(&noColor, "no-color", false, "Disable color output")
	rootCmd.PersistentFlags().BoolVarP(&verbose, "verbose", "v", false, "Verbose output")
	rootCmd.PersistentFlags().BoolVar(&dryRun, "dry-run", false, "Show what would be done without executing")
	rootCmd.PersistentFlags().BoolVarP(&yesFlag, "yes", "y", false, "Skip confirmation prompts")

	// Built-in commands
	rootCmd.AddCommand(versionCmd())
	rootCmd.AddCommand(configCmd())
	rootCmd.AddCommand(&cobra.Command{
		Use:   "completion [bash|zsh|fish|powershell]",
		Short: "Generate shell completion script",
		Long:  "Generate shell completion script for mac.\n\nUsage:\n  mac completion zsh > ~/.zfunc/_mac\n  mac completion bash > /etc/bash_completion.d/mac\n  mac completion fish > ~/.config/fish/completions/mac.fish",
		ValidArgs: []string{"bash", "zsh", "fish", "powershell"},
		Args:      cobra.ExactArgs(1),
		Run: func(cmd *cobra.Command, args []string) {
			switch args[0] {
			case "bash":
				rootCmd.GenBashCompletion(os.Stdout)
			case "zsh":
				rootCmd.GenZshCompletion(os.Stdout)
			case "fish":
				rootCmd.GenFishCompletion(os.Stdout, true)
			case "powershell":
				rootCmd.GenPowerShellCompletionWithDesc(os.Stdout)
			default:
				fmt.Fprintf(os.Stderr, "Unsupported shell: %s\n", args[0])
				os.Exit(1)
			}
		},
	})

	// Register all modules as Cobra subcommands
	registerModules(rootCmd)

	// Global shortcuts (convenience aliases matching the original Bash CLI)
	addShortcuts(rootCmd)

	if err := rootCmd.Execute(); err != nil {
		os.Exit(1)
	}
}

func versionCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "version",
		Short: "Show version information",
		Run: func(cmd *cobra.Command, args []string) {
			w := getOutput()
			w.Header(fmt.Sprintf("SuperMac v%s", version.Version))
			fmt.Printf("  Version:    %s\n", version.Version)
			fmt.Printf("  Build:      %s\n", version.BuildDate)
			fmt.Println()

			modules := module.All()
			names := make([]string, 0, len(modules))
			for name := range modules {
				names = append(names, name)
			}
			sort.Strings(names)
			fmt.Printf("  Modules:    %s\n", strings.Join(names, ", "))
		},
	}
}

func configCmd() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "config",
		Short: "Manage SuperMac configuration",
	}

	cmd.AddCommand(&cobra.Command{
		Use:   "list",
		Short: "Show current configuration",
		Run: func(cmd *cobra.Command, args []string) {
			cfg, err := config.Load()
			if err != nil {
				fmt.Fprintf(os.Stderr, "Error loading config: %v\n", err)
				os.Exit(1)
			}
			w := getOutput()
			if jsonFlag {
				w.JSON(cfg)
				return
			}
			w.Header("SuperMac Configuration")
			fmt.Printf("  Format:   %s\n", cfg.Output.Format)
			fmt.Printf("  Color:    %v\n", cfg.Output.Color)
			fmt.Printf("  Updates:  %v (%s)\n", cfg.Output.Format, cfg.Updates.Channel)
			if len(cfg.Aliases) > 0 {
				fmt.Println("  Aliases:")
				for k, v := range cfg.Aliases {
					fmt.Printf("    %-15s → %s\n", k, v)
				}
			}
		},
	})

	cmd.AddCommand(&cobra.Command{
		Use:   "get <key>",
		Short: "Get a config value",
		Args:  cobra.ExactArgs(1),
		Run: func(cmd *cobra.Command, args []string) {
			cfg, err := config.Load()
			if err != nil {
				fmt.Fprintf(os.Stderr, "Error: %v\n", err)
				os.Exit(1)
			}
			// Simple dot-path lookup
			switch args[0] {
			case "output.format":
				fmt.Println(cfg.Output.Format)
			case "output.color":
				fmt.Println(cfg.Output.Color)
			case "updates.check":
				fmt.Println(cfg.Updates.Check)
			case "updates.channel":
				fmt.Println(cfg.Updates.Channel)
			default:
				fmt.Fprintf(os.Stderr, "Unknown config key: %s\n", args[0])
				os.Exit(1)
			}
		},
	})

	return cmd
}

func registerModules(rootCmd *cobra.Command) {
	modules := module.All()

	for _, mod := range modules {
		modCmd := &cobra.Command{
			Use:   mod.Name(),
			Short: fmt.Sprintf("%s %s", mod.Emoji(), mod.ShortDescription()),
		}

		commands := mod.Commands()
		for _, cmd := range commands {
			cmd := cmd // capture
			subCmd := &cobra.Command{
				Use:   cmd.Name,
				Short: cmd.Description,
				Aliases: cmd.Aliases,
				RunE: func(subCmd *cobra.Command, args []string) error {
					ctx := &module.Context{
						Config:   loadConfig(),
						Output:   getOutput(),
						Platform: getPlatform(),
						Prompt:   getPrompt(),
						Args:     args,
						Flags:    make(map[string]string),
						Verbose:  verbose,
						DryRun:   dryRun,
					}
					return cmd.Run(ctx)
				},
			}
			// Register per-command flags
			for _, flag := range cmd.Flags {
				subCmd.Flags().StringP(flag.Name, flag.Shorthand, flag.DefaultValue, flag.Description)
				if flag.Required {
					subCmd.MarkFlagRequired(flag.Name)
				}
			}
			modCmd.AddCommand(subCmd)
		}

		rootCmd.AddCommand(modCmd)
	}
}

func runHelp(cmd *cobra.Command, args []string) {
	w := getOutput()
	w.Header(fmt.Sprintf("SuperMac v%s", version.Version))
	fmt.Println()
	fmt.Println("Usage: mac <category> <action> [arguments]")
	fmt.Println()

	modules := module.All()
	if len(modules) > 0 {
		names := make([]string, 0, len(modules))
		for name := range modules {
			names = append(names, name)
		}
		sort.Strings(names)

		fmt.Println("Available Categories:")
		for _, name := range names {
			mod := modules[name]
			fmt.Printf("  %-12s %s %s\n", name, mod.Emoji(), mod.ShortDescription())
		}
		fmt.Println()
	}

	fmt.Println("Built-in Commands:")
	fmt.Println("  help           Show this help")
	fmt.Println("  version        Show version information")
	fmt.Println("  config list    Show current configuration")
	fmt.Println()
	fmt.Println("Global Flags:")
	fmt.Println("  --json         Output in JSON format")
	fmt.Println("  --quiet        Suppress output except errors")
	fmt.Println("  --no-color     Disable color output")
	fmt.Println("  --verbose      Verbose output")
	fmt.Println("  --dry-run      Show what would be done")
	fmt.Println("  --yes          Skip confirmation prompts")
	fmt.Println()
	fmt.Println("Built by CosmoLabs — https://cosmolabs.org")
}

func loadConfig() *config.Config {
	cfg, err := config.Load()
